from __future__ import annotations

import argparse
import csv
import re
from datetime import date
from pathlib import Path
from typing import Any

# Build a curated v2 seed set from the FDA AI-list CSV generated by src.ingest_fda_ai_list.
# Goal: avoid another "latest 20" dataset dominated by very new devices / broad hardware families.
# Output schema is compatible with src.ingest_seed_devices.py.

EXPECTED_COLUMNS = [
    "seed_rank",
    "decision_date",
    "submission_number",
    "device_name",
    "company",
    "panel",
    "primary_product_code",
    "fda_database_url",
    "cohort",
    "dataset_v2_score",
    "seed_reason",
]

SOFTWARE_KEYWORDS = [
    "ai", "algorithm", "software", "cad", "caDe", "cadx", "detect", "detection", "triage",
    "quant", "quantification", "segmentation", "assist", "analysis", "viewer", "suite", "platform",
    "stroke", "lung", "nodule", "fracture", "hemorrhage", "embolism", "aneurysm", "cardiac",
    "brain", "liver", "spine", "vertebra", "mammography", "breast", "ct", "mri", "ultrasound",
    "reconstruction", "recon", "notification", "alert", "diagnostic", "planning",
]

# Broad hardware/platform names are useful as negative controls, but poor public demos for AI-specific failure modes.
HARDWARE_KEYWORDS = [
    "magnetom", "signa", "somatom", "scanner", "scanners", "ultrasound system", "diagnostic ultrasound system",
    "portable mr imaging system", "mr imaging system", "x-ray system", "ct system", "pet/ct", "pet mr",
    "mobile c-arm", "c-arm", "radiography system", "fluoroscopy", "imaging system", "tomography system",
]

WEAK_NAME_TERMS = {
    "ai", "air", "dl", "ct", "mr", "mri", "cad", "system", "software", "device", "platform", "imaging", "diagnostic"
}


def norm_col(s: str) -> str:
    return re.sub(r"[^a-z0-9]+", "_", s.strip().lower()).strip("_")


def find_col(fieldnames: list[str], candidates: list[str]) -> str | None:
    normalized = {norm_col(c): c for c in fieldnames}
    for cand in candidates:
        if norm_col(cand) in normalized:
            return normalized[norm_col(cand)]
    return None


def parse_year(value: str | None) -> int | None:
    if not value:
        return None
    m = re.search(r"(20\d{2}|19\d{2})", str(value))
    return int(m.group(1)) if m else None


def token_count(name: str) -> int:
    toks = re.findall(r"[A-Za-z0-9]+", name.lower())
    toks = [t for t in toks if t not in WEAK_NAME_TERMS and len(t) > 2]
    return len(toks)


def contains_any(text: str, keywords: list[str]) -> list[str]:
    t = text.lower()
    return [k for k in keywords if k.lower() in t]


def database_url(submission: str) -> str:
    sub = (submission or "").strip().upper()
    if sub.startswith(("K", "DEN")):
        return f"https://www.accessdata.fda.gov/scripts/cdrh/cfdocs/cfPMN/pmn.cfm?ID={sub}"
    if sub.startswith("P"):
        return f"https://www.accessdata.fda.gov/scripts/cdrh/cfdocs/cfPMA/pma.cfm?id={sub}"
    return f"https://www.accessdata.fda.gov/scripts/cdrh/cfdocs/cfPMN/pmn.cfm?ID={sub}"


def load_rows(path: Path) -> list[dict[str, Any]]:
    with path.open(newline="", encoding="utf-8-sig") as f:
        reader = csv.DictReader(f)
        fieldnames = reader.fieldnames or []
        col_decision = find_col(fieldnames, ["decision_date", "date of final decision", "decision date"])
        col_submission = find_col(fieldnames, ["submission_number", "submission number", "submission"])
        col_device = find_col(fieldnames, ["device_name", "device", "device name"])
        col_company = find_col(fieldnames, ["company", "manufacturer", "applicant"])
        col_panel = find_col(fieldnames, ["panel", "panel (lead)", "medical specialty"])
        col_code = find_col(fieldnames, ["primary_product_code", "primary product code", "product_code", "product code"])
        col_url = find_col(fieldnames, ["fda_database_url", "fda database url", "url"])
        required = [col_decision, col_submission, col_device, col_company, col_panel, col_code]
        if any(c is None for c in required):
            raise SystemExit(f"Could not map input columns. Found columns: {fieldnames}")

        out = []
        for raw in reader:
            sub = (raw.get(col_submission) or "").strip().upper()
            name = (raw.get(col_device) or "").strip()
            if not sub or not name:
                continue
            row = {
                "decision_date": (raw.get(col_decision) or "").strip(),
                "submission_number": sub,
                "device_name": name,
                "company": (raw.get(col_company) or "").strip(),
                "panel": (raw.get(col_panel) or "").strip() or "Radiology",
                "primary_product_code": (raw.get(col_code) or "").strip().upper(),
                "fda_database_url": (raw.get(col_url) or "").strip() or database_url(sub),
            }
            out.append(row)
        return out


def score_row(row: dict[str, Any]) -> tuple[int, str, str]:
    name = row["device_name"]
    text = f"{name} {row.get('company','')} {row.get('primary_product_code','')}"
    year = parse_year(row.get("decision_date"))
    sw = contains_any(text, SOFTWARE_KEYWORDS)
    hw = contains_any(text, HARDWARE_KEYWORDS)
    name_specificity = token_count(name)

    score = 0
    reasons = []

    if year and year <= 2023:
        score += 30
        reasons.append("older_clearance")
    elif year and year <= 2024:
        score += 15
        reasons.append("moderately_old_clearance")
    else:
        score -= 10
        reasons.append("recent_or_unknown_clearance")

    if sw:
        score += min(30, 6 * len(set(sw)))
        reasons.append("software_ai_keywords:" + "/".join(sorted(set(sw))[:5]))

    if name_specificity >= 3:
        score += 15
        reasons.append("specific_device_name")
    elif name_specificity <= 1:
        score -= 15
        reasons.append("weak_or_generic_name")

    if hw:
        score -= 25
        reasons.append("hardware_family_keywords:" + "/".join(sorted(set(hw))[:5]))

    if len(name) > 90 or ";" in name:
        score -= 10
        reasons.append("long_family_name")

    if hw:
        cohort = "negative_control_hardware_family"
    elif year and year >= 2025:
        cohort = "recent_sparse_device"
    else:
        cohort = "software_first_candidate"
    return score, cohort, "; ".join(reasons)


def dedupe_by_submission(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    seen = set()
    out = []
    for row in rows:
        sub = row["submission_number"]
        if sub in seen:
            continue
        seen.add(sub)
        out.append(row)
    return out


def select(rows: list[dict[str, Any]], target_software: int, target_controls: int, target_recent: int) -> list[dict[str, Any]]:
    scored = []
    for row in rows:
        if row.get("panel", "").lower() != "radiology":
            continue
        score, cohort, reason = score_row(row)
        row = dict(row)
        row["dataset_v2_score"] = score
        row["cohort"] = cohort
        row["seed_reason"] = reason
        scored.append(row)

    software = sorted([r for r in scored if r["cohort"] == "software_first_candidate"], key=lambda r: r["dataset_v2_score"], reverse=True)[:target_software]
    controls = sorted([r for r in scored if r["cohort"] == "negative_control_hardware_family"], key=lambda r: r["dataset_v2_score"], reverse=True)[:target_controls]
    recent = sorted([r for r in scored if r["cohort"] == "recent_sparse_device"], key=lambda r: r["dataset_v2_score"], reverse=True)[:target_recent]
    combined = dedupe_by_submission(software + controls + recent)
    combined = sorted(combined, key=lambda r: (r["cohort"], -int(r["dataset_v2_score"]), r.get("decision_date") or ""))
    for i, row in enumerate(combined, 1):
        row["seed_rank"] = i
    return combined


def write_rows(rows: list[dict[str, Any]], path: Path) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open("w", newline="", encoding="utf-8") as f:
        writer = csv.DictWriter(f, fieldnames=EXPECTED_COLUMNS, extrasaction="ignore")
        writer.writeheader()
        for row in rows:
            writer.writerow(row)


def main() -> None:
    parser = argparse.ArgumentParser(description="Build a curated AIMD Sentinel v2 seed dataset from an FDA AI-list CSV.")
    parser.add_argument("--input", default="data/fda_ai_list_radiology_top300.csv")
    parser.add_argument("--out", default="data/seed_devices_v2.csv")
    parser.add_argument("--target-software", type=int, default=40)
    parser.add_argument("--target-controls", type=int, default=10)
    parser.add_argument("--target-recent", type=int, default=10)
    args = parser.parse_args()

    rows = load_rows(Path(args.input))
    selected = select(rows, args.target_software, args.target_controls, args.target_recent)
    write_rows(selected, Path(args.out))

    counts: dict[str, int] = {}
    for r in selected:
        counts[r["cohort"]] = counts.get(r["cohort"], 0) + 1
    print(f"Wrote {len(selected)} rows to {args.out}")
    for k, v in sorted(counts.items()):
        print(f"  {k}: {v}")
    print("\nReview this CSV before ingestion. Remove obvious broad hardware families from public-demo candidates; keep some as negative controls.")


if __name__ == "__main__":
    main()
